// C: LUA_API int lua_absindex (lua_State *L, int idx)
pub fn abs_index(state: &LuaState, idx: i32) -> i32 {
    // C: return (idx > 0 || ispseudo(idx)) ? idx
    //          : cast_int(L->top.p - L->ci->func.p) + idx;
    if idx > 0 || is_pseudo(idx) {
        idx
    } else {
