    }
    pub fn ci_savedpc(&self, idx: CallInfoIdx) -> u32 { self.call_info[idx.as_usize()].saved_pc() }
    pub fn set_ci_savedpc(&mut self, idx: CallInfoIdx, pc: u32) {
