    pub u2: CallInfoExtra,

    // C: short nresults
    // types.tsv: CallInfo.nresults → i16
    pub nresults: i16,

    // C: unsigned short callstatus
    // types.tsv: CallInfo.callstatus → u16 (bit-packed CIST_* flags)
    pub callstatus: u16,
}

/// Payload of `CallInfo.u`.
