    ///
    /// PORT NOTE: C uses `g->nilvalue` being nil as the "complete" signal.
    /// We replicate the same logic: `nilvalue == Nil` means complete.
    pub fn is_complete(&self) -> bool {
        // C: ttisnil(&g->nilvalue)
        matches!(self.nilvalue, LuaValue::Nil)
